+import type { ConfigurableTrait, Trait, TraitRecord } from '../trait/types';
+import type { DeferredCommand, DeferredWorld, World } from './types';
+
+function currentBuffer(world: World) {
+    const buffers = world[$internal].deferredBuffers;
+    return buffers[buffers.length - 1];
+}
+
+export function createDeferredWorld(world: World): DeferredWorld {
+    return {
+        spawn(...traits) {
+            const entity = reserveEntity(world);
+            currentBuffer(world).push({ type: 'spawn', entity, traits });
+            return entity;
+        },
+        destroy(entity) {
+            currentBuffer(world).push({ type: 'destroy', entity });
+        },
+        add(entity, ...traits) {
+            currentBuffer(world).push({ type: 'add', entity, traits });
+        },
+        remove(entity, ...traits) {
+            currentBuffer(world).push({ type: 'remove', entity, traits });
+        },
+        addExclusive(entity, pair) {
+            currentBuffer(world).push({ type: 'exclusive', entity, pair });
+        },
+        flush() {
+            flushDeferred(world);
+        },
+    };
+}
+
+export function pushDeferredScope(world: World) {
+    world[$internal].deferredBuffers.push([]);
+}
+
+export function popDeferredScope(world: World) {
+    flushDeferred(world);
+    world[$internal].deferredBuffers.pop();
+}
+
+export function flushDeferredForEntity(world: World, entity: Entity) {
+    const buffers = world[$internal].deferredBuffers;
+    for (let i = 0; i < buffers.length; i++) {
+        if (buffers[i].some((command) => command.entity === entity)) {
+            flushDeferred(world, buffers[i]);
+        }
+    }
+}
+
+export function flushDeferred(world: World, buffer = currentBuffer(world)) {
+    if (!buffer.length || world[$internal].isFlushingDeferred) return;
+    const ctx = world[$internal];
+    const commands = buffer.splice(0);
+    const nullified = new Set<Entity>();
+    for (const command of commands) {
+        if (command.type === 'destroy' && ctx.deferredSpawns.has(command.entity)) nullified.add(command.entity);
+    }
+
+    ctx.isFlushingDeferred = true;
+    try {
+        for (const command of commands) {
+            const entity = command.entity;
+            if (nullified.has(entity)) continue;
+            if (command.type === 'spawn') {
+                if (!ctx.deferredSpawns.has(entity)) continue;
+                activateDeferredEntity(world, entity, ...command.traits);
+                ctx.deferredSpawns.delete(entity);
+                continue;
+            }
+            if (entity === ctx.worldEntity && command.type === 'destroy') {
+                throw new Error('Koota: The world entity cannot be destroyed through deferred commands.');
+            }
+            if (ctx.deferredSpawns.has(entity) || !world.has(entity)) continue;
+            if (command.type === 'destroy') destroyEntity(world, entity);
+            else if (command.type === 'add') addTrait(world, entity, ...command.traits);
+            else if (command.type === 'remove') removeTrait(world, entity, ...command.traits);
+            else {
+                const pairCtx = command.pair[$internal];
+                removeTrait(world, entity, pairCtx.relation('*'));
+                if (pairCtx.target !== '*') addTrait(world, entity, command.pair);
+            }
+        }
+    } finally {
+        ctx.isFlushingDeferred = false;
+        for (const entity of nullified) {
+            ctx.deferredSpawns.delete(entity);
+            ctx.entityTraits.delete(entity);
+            releaseEntity(ctx.entityIndex, entity);
+            const eid = getEntityId(entity);
+            for (const mask of ctx.entityMasks) mask[eid] = 0;
+        }
+    }
+}
+
+/** Predicting deferred state keeps entity.has/get useful without making mutations observable. */
+export function hasDeferredTrait(world: World, entity: Entity, trait: Trait | any): boolean | undefined {
+    const commands = currentBuffer(world).filter((command) => command.entity === entity);
+    if (!commands.length) return undefined;
+    let result = isRelationPair(trait) ? entity.has(trait) : hasTrait(world, entity, trait);
+    for (const command of commands) {
+        if (command.type === 'destroy') return false;
+        if (command.type === 'spawn') result = command.traits.some((value) => matches(value, trait));
+        if (command.type === 'add' && command.traits.some((value) => matches(value, trait))) result = true;
+        if (command.type === 'remove' && command.traits.some((value) => matches(value, trait))) result = false;
+        if (command.type === 'exclusive' && isRelationPair(trait)) {
+            const relation = trait[$internal].relation;
+            if (relation === command.pair[$internal].relation) result = matches(command.pair, trait);
+        }
+    }
+    return result;
+}
+
+function matches(config: ConfigurableTrait | Trait | any, trait: Trait | any) {
+    if (isRelationPair(config) || isRelationPair(trait)) {
+        if (!isRelationPair(config) || !isRelationPair(trait)) return false;
+        const a = config[$internal];
+        const b = trait[$internal];
+        return a.relation === b.relation && (a.target === '*' || a.target === b.target);
+    }
+    return (Array.isArray(config) ? config[0] : config) === trait;
+}
+
+export function getDeferredTrait(world: World, entity: Entity, trait: Trait | any): TraitRecord<any> | undefined {
+    const has = hasDeferredTrait(world, entity, trait);
+    if (has === undefined) return undefined;
+    if (!has) return undefined;
+    let value = getTrait(world, entity, trait) as any;
+    const base = isRelationPair(trait) ? trait[$internal].relation[$internal].trait : trait;
+    if (!value && base[$internal].type !== 'tag') value = getSchemaDefaults(base.schema, base[$internal].type) ?? {};
+    for (const command of currentBuffer(world)) {
+        if (command.entity !== entity || command.type === 'remove' || command.type === 'destroy') continue;
+        const traits = command.type === 'spawn' || command.type === 'add' ? command.traits : [command.pair];
+        for (const config of traits) {
+            if (matches(config, trait) && Array.isArray(config)) value = { ...value, ...config[1] };
+            else if (matches(config, trait) && isRelationPair(config) && config[$internal].params)
+                value = { ...value, ...config[$internal].params };
+        }
+    }
+    return value;
+}
