+type SubscriptionSnapshot = Map<Entity, Map<Trait, Entity[] | boolean>>;
+
+function snapshotSubscriptions(world: World, commands: DeferredCommand[]): SubscriptionSnapshot {
+    const snapshot: SubscriptionSnapshot = new Map();
+    for (const { entity } of commands) {
+        if (snapshot.has(entity)) continue;
+        const traits = world[$internal].entityTraits.get(entity);
+        const state = new Map<Trait, Entity[] | boolean>();
+        if (traits) {
+            for (const trait of traits) {
+                const relation = trait[$internal].relation;
+                state.set(trait, relation ? getRelationTargets(world, relation, entity) : true);
+            }
+        }
+        snapshot.set(entity, state);
+    }
+    return snapshot;
+}
