+function emitSubscriptionDiff(world: World, before: SubscriptionSnapshot) {
+    for (const [entity, prior] of before) {
+        const after = snapshotSubscriptions(world, [{ type: 'destroy', entity }]).get(entity)!;
+        const traits = new Set([...prior.keys(), ...after.keys()]);
+        for (const trait of traits) {
+            const instance = getTraitInstance(world[$internal].traitInstances, trait);
